#include <iostream>
#include <vector>
#include <climits>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;

    vector<vector<int>> a(n, vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            cin >> a[i][j];
        }
    }

    int max_main = INT_MIN;
    int min_secondary = INT_MAX;

    for (int i = 0; i < n; ++i) {
        // main diagonal: row i, column i
        if (a[i][i] > max_main) max_main = a[i][i];
        // secondary diagonal: row i, column n-1-i
        if (a[i][n - 1 - i] < min_secondary) min_secondary = a[i][n - 1 - i];
    }

    cout << max_main - min_secondary << '\n';

    return 0;
}
